using namespace vl;
using namespace vl::inter_process::windows_http;

EventObject completed;
CHECK_ERROR(completed.CreateManualUnsignal(false), L"Failed to create the completion event.");

HttpClientApi client(L"vczh-libraries.github.io", 443);
HttpRequest request;
request.method = L"GET";
request.query = L"/";
request.secure = true;
request.acceptTypes.Add(L"text/html");

client.HttpQuery(request, [&](Variant<HttpResponse, HttpError> result)
{
    if (auto response = result.TryGet<HttpResponse>())
    {
        Console::WriteLine(itow(response->statusCode));
        Console::WriteLine(response->GetBodyUtf8());
    }
    else
    {
        Console::WriteLine(result.Get<HttpError>().message);
    }
    completed.Signal();
});

completed.Wait();
